#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=800005;
int tr[N],tag[N],num[N]; // 线段树 
int n,m,r,p,w[N]; //输入
int id[N],fa[N],cnt,dep[N],siz[N];
int zson[N],top[N];//树链 
vector<int> g[N];
void pushup(int id)
{
	tr[id]=(tr[id<<1]+tr[(id<<1)|1])%p;
}
void pushdown(int id,int len)
{
	int ls=id<<1,rs=id<<1|1;
	tag[ls]+=tag[id];
	tag[rs]+=tag[id];
	tr[ls]+=tag[id]*(len-(len>>1));
	tr[rs]+=tag[id]*(len>>1);
	tr[ls]%=p;
	tr[rs]%=p;
	tag[id]=0;
}
void build(int id,int l,int r)
{
	if(l==r)
	{
		tr[id]=num[l];
		tr[id]%=p;
		return ;
	}
	int mid=(l+r)>>1;
	build(id<<1,l,mid);
	build(id<<1|1,mid+1,r);
	pushup(id);
}
int query(int id,int l,int r,int x,int y)
{
	if(x<=l&&y>=r)
	{
		return tr[id]; 
	}
	int mid=(l+r)>>1;
	if(tag[id]) pushdown(id,r-l+1);
	int sum=0;
	if(x<=mid) sum+=query(id<<1,l,mid,x,y);
	if(y>mid) sum+=query(id<<1|1,mid+1,r,x,y);
	return sum%p;
}
void update(int id,int l,int r,int x,int y,int k)
{
	if(x<=l&&y>=r)
	{
		tag[id]+=k;
		tr[id]+=k*(r-l+1);
		return ;
	}
	int mid=(l+r)>>1;
	if(tag[id]) pushdown(id,r-l+1);
	if(x<=mid) update(id<<1,l,mid,x,y,k);
	if(y>mid) update(id<<1|1,mid+1,r,x,y,k);
	pushup(id);
}
int lian_query(int x,int y)
{
	int sum=0;
	while(top[x]!=top[y])
	{
		if(dep[top[x]]<dep[top[y]]) swap(x,y);
		sum=(sum+query(1,1,n,id[top[x]],id[x]))%p;
		x=fa[top[x]];
	}
	if(dep[x]>dep[y]) swap(x,y);
	sum=(sum+query(1,1,n,id[x],id[y]))%p;
	return sum;
}
void lian_update(int x,int y,int k)
{
	k%=p;
	while(top[x]!=top[y])
	{
		if(dep[top[x]]<dep[top[y]]) swap(x,y);
		update(1,1,n,id[top[x]],id[x],k);
		x=fa[top[x]];
	}
	if(dep[x]>dep[y]) swap(x,y);
	update(1,1,n,id[x],id[y],k);
}
void dfs1(int u,int f,int depp)
{
//	cout<<"--- dfs1 : "<<u<<" "<<f<<' '<<depp<<"\n";
	dep[u]=depp;
	fa[u]=f;
	siz[u]=1;
	int mx=-1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		dfs1(v,u,depp+1);
		siz[u]+=siz[v];
//		cout<<v<<" siz : "<<siz[v]<<"\n";
		if(siz[v]>mx) zson[u]=v,mx=siz[v];
	}
}
void dfs2(int u,int numm)
{
//	cout<<u<<"  ----dfs2\n";
	id[u]=++cnt;
	num[cnt]=w[u];
	top[u]=numm;
//	cout<<"zson ? \n";
	if(!zson[u])
	{
//		cout<<"   return ;\n";
		return ;
	}
//	cout<<"Yes!\n";
	dfs2(zson[u],numm);
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==fa[u]||v==zson[u]) continue;
		dfs2(v,v);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>r>>p;
	for(int i=1;i<=n;i++) cin>>w[i];
	for(int i=1;i<n;i++)
	{
		int x,y;
		cin>>x>>y;
		g[x].push_back(y);
		g[y].push_back(x);
	}
	dfs1(r,0,1);
	dfs2(r,r);
//	cout<<"aaa"<<endl;
	build(1,1,n);
//	cout<<"bbb"<<endl<<"id : ";
//	for(int i=1;i<=n;i++) cout<<id[i]<<" ";
//	cout<<"\n";
	while(m--)
	{
//		cout<<"---"<<m<<endl;
		int k,x,y,z;
		cin>>k;
		if(k==1)
		{
			cin>>x>>y>>z;
			lian_update(x,y,z);
		}
		else if(k==2)
		{
			cin>>x>>y;
			cout<<lian_query(x,y)<<'\n';
		}
		else if(k==3)
		{
			cin>>x>>y;
			update(1,1,n,id[x],id[x]+siz[x]-1,y);
		}
		else
		{
			cin>>x;
//			cout<<"aaaaaa"<<endl;
			cout<<query(1,1,n,id[x],id[x]+siz[x]-1)<<'\n';
		}
//		cout<<"---"<<m<<endl;
	}
	return 0;
}
